 * Classification Engine - Main Entry Point
 *
 * Sophisticated 9-stage email classification pipeline extracted from n8n workflows.
 * Preserves all classification sophistication while enabling direct Node.js execution.
 */

// Main API class for REST endpoints (stub implementation for TDD)
export { ClassificationEngine } from './classification-engine';

// Main classification pipeline orchestrator (to be implemented)
export { ClassificationPipeline } from './pipeline';

// Individual pipeline stages (all stages export their functions and types)
export * from './stages';

// Core entity types (exported separately to avoid re-export ambiguity)
export type {
  EmailMessage,
  EmailProcessingState,
  EmailHeader,
  EmailAddress,
  MessagePartBody,
  MessagePart,
  EmailAttachment,
} from './types/email-message';

export type {
  ClassificationSession,
  ProcessingMode,
  SessionPerformanceMetrics,
  ClassificationError,
} from './types/classification-session';

export type {
  ClassificationResult,
  ConfidenceLevel,
  CategoryAssignmentType,
  DetailedClassificationResult,
  SelectedLabel,
  PipelineSelectionSummary,
  CandidateScore,
} from './types/classification-result';

export type {
  ExplainabilityTrace,
  CompleteExplainabilityTrace,
  HardAssertionResult,
  StrongIndicatorResult,
  CategoryRuleResult,
  SubtypeScore,
  RuleScoringMatch,
} from './types/explainability-trace';

export type { ScoreBreakdown, CategoryScoreDetails, DetailedScoreBreakdown } from './types/score-breakdown';

export type {
  AttributeContext,
  ExtendedAttributeContext,
  AttributeDetectionMetadata,
  AttributeInfluenceApplication,
  DerivedAttributeResult,
  AttributeRelationship,
} from './types/attribute-context';

export type {
  CategoryConfiguration,
  ProcessingConfig,
  ValidatedCategoryConfiguration,
  AttributeDetector,
  DerivedAttribute,
  TopLevelCategory,
  SubtypeDefinition,
  RulePattern,
  AttributeRelevanceMatrix,
} from './types/category-configuration';

// Configuration schemas (values, not just types)
export { CategoryConfigurationSchema } from './types/category-configuration';

// API types
export type {
  EmailContent,
  BatchClassificationRequest,
  BatchClassificationResponse,
  BatchClassificationResult,
  SingleClassificationRequest,
  SingleClassificationResponse,
  ConfigValidationRequest,
  ConfigValidationResponse,
  ValidationError,
  ValidationWarning,
} from './types/api-types';

// Utility functions for reuse
export * from './utils/email-utils';

// Configuration system (exported separately to avoid conflicts)
export { configLoader } from './config/config-loader';

