import { Pool } from 'pg';
import {
  EmailMessage,
  EmailAddress,
  EmailHeader,
  MessagePart,
  MessagePartBody,
} from '../../../classification-engine/src/types/email-message';
import * as fs from 'fs';
import * as dotenv from 'dotenv';
import * as path from 'path';

/**

/**
 * Classification Engine Integration Orchestrator (T041)
 *
 * Cross-package integration between email-processor and classification-engine.
 * Coordinates classification pipeline execution and result aggregation.
 *
 * Features:
 * - Single and batch email classification
 * - Result aggregation from 9-stage pipeline
 * - Explainability trace handling
 * - Error handling with partial failure support
 * - Performance metrics preservation
 */

import {
  ClassificationPipeline,
  ClassificationErrorResult,
} from '../../../classification-engine/src/pipeline/classification-pipeline';
import { EmailMessage } from '../../../classification-engine/src/types/email-message';
import { ClassificationResult } from '../../../classification-engine/src/types/classification-result';
import { CategoryConfiguration } from '../../../classification-engine/src/types/category-configuration';

/**
 * Classification Orchestrator
 *

/**
 * Minimal Classification Result Persistence (T036j)
 *
 * Write classification results to database - no batch optimization or advanced session management.
 * Defers comprehensive persistence capabilities to full T042-T044 implementation.
 *
 * Core Functions:
 * - saveClassificationResult: Persist single classification result with transaction safety
 * - saveClassificationBatch: Persist multiple results in single transaction
 *
 * Database Tables:
 * - email.classification_session: Main session record with final classification results
 * - email.classification_stage: Individual stage results with timing metadata
 * - email.stage_category_eval: Per-category score breakdown for each stage
 *
 * Transaction Safety: All inserts for single email wrapped in transaction (rollback on error)
 */

