/**
 * Email Processing Orchestrator (T040)
 *
 * Coordinates batch processing of emails through the complete pipeline:
 * 1. Fetch emails from Gmail API
 * 2. Classify using classification engine
 * 3. Persist results to database
 *
 * Features:
 * - Batch processing with error resilience
 * - Performance metrics tracking
 * - Configurable batch options (max emails, date ranges)
 * - Graceful error handling (continue on individual failures)
 */

import { EmailMessage } from '../../../classification-engine/src/types/email-message';
import { ClassificationResult } from '../../../classification-engine/src/types/classification-result';
import { ProcessingConfig } from '../../../classification-engine/src/types/category-configuration';

/**
 * Gmail client interface for email fetching
 * Full implementation in T037-T038
 */
export interface GmailClient {
  /**
   * Fetch emails with optional filters
   */
  fetchEmails(options: FetchOptions): Promise<EmailMessage[]>;

  /**
   * Fetch single email by ID
   */
  fetchEmailById(messageId: string): Promise<EmailMessage>;
}

/**
 * Classification orchestrator interface for cross-package integration
 * Full implementation in T041
 */
export interface ClassificationOrchestrator {
  /**
   * Classify batch of emails
   */
  classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>>;

  /**
   * Classify single email
   */
  classify(email: EmailMessage): Promise<ClassificationResult>;
}

/**
 * Persistence interface for saving classification results
 * Uses existing T036j implementation (classification-writer.ts)
 */
export interface PersistenceService {
  /**
   * Save batch of classification results
   */
  saveClassificationBatch(results: Map<string, ClassificationResult>): Promise<void>;

  /**
   * Save single classification result
   */
  saveClassificationResult(messageId: string, result: ClassificationResult): Promise<void>;
}

/**
 * Classification error result for batch processing
 */
export interface ClassificationErrorResult {
  error: Error;
  emailId: string;
  processingDurationMs: number;
}

/**
 * Options for fetching emails
 */
export interface FetchOptions {
  maxEmails?: number;
  startDate?: Date;
  endDate?: Date;
  unclassifiedOnly?: boolean;
}

/**
 * Result of batch processing operation
 */
export interface BatchProcessingResult {
  totalProcessed: number;
  successCount: number;
  errorCount: number;
  processingDurationMs: number;
  averageEmailDurationMs: number;
  errors: Array<{
    emailId: string;
    error: Error;
  }>;
}

/**
 * Result of single email processing
 */
export interface SingleProcessingResult {
  success: boolean;
  emailId: string;
  classificationResult?: ClassificationResult;
  error?: Error;
  processingDurationMs: number;
}

/**
 * Email Processing Orchestrator
 *
 * Main service coordinating email processing pipeline with error handling
 * and performance tracking.
 */
export class EmailProcessor {
  private readonly gmailClient: GmailClient;
  private readonly classificationOrchestrator: ClassificationOrchestrator;
  private readonly persistence: PersistenceService;
  private readonly config: ProcessingConfig;

  /**
   * Initialize email processor with dependencies
   *
   * @param gmailClient - Gmail API client for fetching emails
   * @param classificationOrchestrator - Classification engine orchestrator
   * @param persistence - Persistence service for saving results
   * @param config - Processing configuration
   * @throws {Error} If configuration validation fails
   */
  constructor(
    gmailClient: GmailClient,
    classificationOrchestrator: ClassificationOrchestrator,
    persistence: PersistenceService,
    config: ProcessingConfig
  ) {
    // Validate configuration
    this.validateConfig(config);

    this.gmailClient = gmailClient;
    this.classificationOrchestrator = classificationOrchestrator;
    this.persistence = persistence;
    this.config = config;
  }

  /**
   * Validate processing configuration
   *
   * @param config - Configuration to validate
   * @throws {Error} If configuration is invalid
   */
  private validateConfig(config: ProcessingConfig): void {
    if (!config) {
      throw new Error('Invalid configuration: config is required');
    }

    if (!config.confidenceThresholds) {
      throw new Error('Invalid configuration: confidenceThresholds is required');
    }

    if (!config.settings) {
      throw new Error('Invalid configuration: settings is required');
    }

    // Validate required nested settings
    if (!config.settings.multiLabelSelection) {
      throw new Error('Invalid configuration: settings.multiLabelSelection is required');
    }

    if (!config.multiLabelPolicy) {
      throw new Error('Invalid configuration: multiLabelPolicy is required');
    }
  }

  /**
   * Process batch of emails through complete pipeline
   *
   * Workflow:
   * 1. Fetch emails from Gmail
   * 2. Classify emails in batch
   * 3. Persist successful results
   * 4. Return summary with errors
   *
   * @param options - Fetch options for email retrieval
   * @returns Batch processing result with metrics
   */
  async processBatch(options: FetchOptions): Promise<BatchProcessingResult> {
    const startTime = Date.now();
    const errors: Array<{ emailId: string; error: Error }> = [];

    try {
      // 1. Fetch emails
      const emails = await this.gmailClient.fetchEmails(options);

      if (emails.length === 0) {
        return {
          totalProcessed: 0,
          successCount: 0,
          errorCount: 0,
          processingDurationMs: Date.now() - startTime,
          averageEmailDurationMs: 0,
          errors: [],
        };
      }

      // 2. Classify emails in batch
      const classificationResults = await this.classificationOrchestrator.classifyBatch(emails);

      // 3. Separate successful results from errors
      const successfulResults = new Map<string, ClassificationResult>();

      classificationResults.forEach((result, index) => {
        if ('error' in result) {
          // Classification failed for this email
          errors.push({
            emailId: result.emailId,
            error: result.error,
          });
        } else {
          // Classification succeeded
          successfulResults.set(emails[index].id, result);
        }
      });

      // 4. Persist successful results
      if (successfulResults.size > 0) {
        await this.persistence.saveClassificationBatch(successfulResults);
      }

      // 5. Calculate metrics
      const endTime = Date.now();
      const totalDuration = endTime - startTime;
      const totalProcessed = emails.length;
      const successCount = successfulResults.size;
      const errorCount = errors.length;
      const averageEmailDurationMs = totalProcessed > 0 ? totalDuration / totalProcessed : 0;

      return {
        totalProcessed,
        successCount,
        errorCount,
        processingDurationMs: totalDuration,
        averageEmailDurationMs,
        errors,
      };
    } catch (error) {
      // Fatal error during batch processing
      throw new Error(`Batch processing failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Process single email through complete pipeline
   *
   * Workflow:
   * 1. Fetch email from Gmail
   * 2. Classify email
   * 3. Persist result
   * 4. Return result with metrics
   *
   * @param messageId - Gmail message ID
   * @returns Single processing result
   */
  async processSingle(messageId: string): Promise<SingleProcessingResult> {
    const startTime = Date.now();

    try {
      // 1. Fetch email
      const email = await this.gmailClient.fetchEmailById(messageId);

      // 2. Classify email
      const classificationResult = await this.classificationOrchestrator.classify(email);

      // 3. Persist result
      await this.persistence.saveClassificationResult(messageId, classificationResult);

      // 4. Return success result
      return {
        success: true,
        emailId: messageId,
        classificationResult,
        processingDurationMs: Date.now() - startTime,
      };
    } catch (error) {
      // Return error result
      return {
        success: false,
        emailId: messageId,
        error: error instanceof Error ? error : new Error(String(error)),
        processingDurationMs: Date.now() - startTime,
      };
    }
  }

  /**
   * Get current configuration
   *
   * @returns Processing configuration
   */
  getConfig(): ProcessingConfig {
    return this.config;
  }
}

